import{c as i,O as a,i as e,m as n}from"./chunks/framework.BWIk71Uc.js";const c=JSON.parse('{"title":"Chapter 1 · Setting Up the Development Environment","description":"","frontmatter":{},"headers":[],"relativePath":"en/notes/spring/mysql-integration/environment.md","filePath":"en/notes/spring/mysql-integration/environment.md","lastUpdated":1779888725000}'),t={name:"en/notes/spring/mysql-integration/environment.md"};function l(h,s,p,r,o,k){return a(),e("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1779888725000"},[...s[0]||(s[0]=[n(`<h1 id="chapter-1-·-setting-up-the-development-environment" tabindex="-1">Chapter 1 · Setting Up the Development Environment <a class="header-anchor" href="#chapter-1-·-setting-up-the-development-environment" aria-label="Permalink to “Chapter 1 · Setting Up the Development Environment”">​</a></h1><p><a href="./">Previous: Overview</a> | <a href="./database-design.html">Next: Database Design</a></p><hr><h3 id="_1-1-objective" tabindex="-1">1.1 Objective <a class="header-anchor" href="#_1-1-objective" aria-label="Permalink to “1.1 Objective”">​</a></h3><p>Get the following components up and running, and ensure they can communicate with each other:</p><ul><li>MySQL 8.x (localhost:3306)</li><li>Nacos (localhost:8848)</li><li>Sentinel Dashboard (localhost:8081)</li><li>Docker daemon (required for the Testcontainers phase later)</li><li>The project itself can pass <code>mvn clean compile</code></li></ul><h3 id="_1-2-install-mysql-8-x" tabindex="-1">1.2 Install MySQL 8.x <a class="header-anchor" href="#_1-2-install-mysql-8-x" aria-label="Permalink to “1.2 Install MySQL 8.x”">​</a></h3><blockquote><p>Skip if already installed. Windows / macOS users are recommended to use the community edition installer; WSL users can use <code>sudo apt install mysql-server-8.0</code>.</p></blockquote><p>After installation, verify:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mysql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Example output: mysql  Ver 8.0.x for ...</span></span></code></pre></div><h3 id="_1-3-one-time-database-and-account-creation" tabindex="-1">1.3 One-time Database and Account Creation <a class="header-anchor" href="#_1-3-one-time-database-and-account-creation" aria-label="Permalink to “1.3 One-time Database and Account Creation”">​</a></h3><p>Log in as root and run the following SQL:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> DATABASE</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> stock_db</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> DEFAULT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CHARSET utf8mb4 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COLLATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> utf8mb4_unicode_ci;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> DATABASE</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> order_db</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> DEFAULT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CHARSET utf8mb4 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COLLATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> utf8mb4_unicode_ci;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> USER</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &#39;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">stock_app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&#39;@</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;%&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> IDENTIFIED </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">BY</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;stock_app_pwd&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> USER</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &#39;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">order_app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&#39;@</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;%&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> IDENTIFIED </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">BY</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;order_app_pwd&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GRANT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ALL PRIVILEGES </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> stock_db.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;stock_app&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;%&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GRANT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ALL PRIVILEGES </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> order_db.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;order_app&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;%&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">FLUSH PRIVILEGES;</span></span></code></pre></div><blockquote><p>💡 <strong>Why not include this SQL in Flyway as well?</strong> Because <code>CREATE DATABASE</code> / <code>CREATE USER</code> are <strong>privileged operations</strong> that require the root account to execute. Letting Flyway run as root would violate the &quot;principle of least privilege for application accounts&quot;; it&#39;s also impossible for an application account to create its own database and grant itself permissions. Therefore, the correct approach is to treat &quot;database and account creation&quot; as a one-time DBA operation, performed manually or by infrastructure tools like Ansible/Terraform. Flyway should only be responsible for DDL/DML within the schema.</p></blockquote><h3 id="_1-4-verify-account-isolation-is-effective" tabindex="-1">1.4 Verify Account Isolation is Effective <a class="header-anchor" href="#_1-4-verify-account-isolation-is-effective" aria-label="Permalink to “1.4 Verify Account Isolation is Effective”">​</a></h3><p>This is the most easily overlooked but crucial step in this tutorial:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Log in as stock_app and attempt to access order_db</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mysql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ustock_app</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Enter password: stock_app_pwd</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mysql</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt; </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">SELECT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> *</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> FROM</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> order_db.order_info</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LIMIT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Expected: ERROR 1142 or 1044, access denied</span></span></code></pre></div><p>If no error occurs, it means the permissions granted are too broad. Go back and check the <code>GRANT</code> statements.</p><h3 id="_1-5-confirm-nacos-and-sentinel-are-ready" tabindex="-1">1.5 Confirm Nacos and Sentinel are Ready <a class="header-anchor" href="#_1-5-confirm-nacos-and-sentinel-are-ready" aria-label="Permalink to “1.5 Confirm Nacos and Sentinel are Ready”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Nacos console should be accessible</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">open</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8848/nacos</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Default username/password: nacos/nacos</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Sentinel console should be accessible</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">open</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8081</span></span></code></pre></div><p>In Nacos, confirm that the namespace <code>spring-cloud-learning</code> exists. Create it if it doesn&#39;t.</p><h3 id="_1-6-install-docker" tabindex="-1">1.6 Install Docker <a class="header-anchor" href="#_1-6-install-docker" aria-label="Permalink to “1.6 Install Docker”">​</a></h3><p>Integration tests in Phase E will use Testcontainers to temporarily pull a MySQL container. Locally, you need:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ps</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # If no error, the daemon is running</span></span></code></pre></div><p>⚠️ <strong>Pitfall Alert</strong>: WSL2 users using Docker Desktop for Windows need to check &quot;Enable integration with my default WSL distro&quot; in Docker Desktop settings. Otherwise, <code>docker ps</code> in WSL will report a connection refused error.</p><p>✅ <strong>Chapter 1 Self-Check</strong></p><ol><li>Can <code>stock_app</code> SELECT tables in its own stock_db? Can it CREATE TABLE? Why is this permission needed?</li><li>What are the consequences of forgetting to execute <code>FLUSH PRIVILEGES</code>?</li><li>If MySQL is changed to listen on <code>127.0.0.1</code> instead of <code>0.0.0.0</code>, will local access be affected? What about Testcontainers running inside Docker?</li></ol><hr><p><strong>Next Chapter</strong>: <a href="./database-design.html">Database Design (Chapters 2-3)</a></p>`,29)])])}const g=i(t,[["render",l]]);export{c as __pageData,g as default};
